function e(e=``){return String(e).replace(/<style[\s\S]*?<\/style>/gi,` `).replace(/<script[\s\S]*?<\/script>/gi,` `).replace(/<[^>]+>/g,` `).replace(/&nbsp;|&#160;/gi,` `).replace(/&amp;/gi,`&`).replace(/&lt;/gi,`<`).replace(/&gt;/gi,`>`).replace(/&quot;/gi,`"`).replace(/&#39;/gi,`'`)}function t(t={}){if(t.reading_time)return t.reading_time;let n=[t.content,t.excerpt,t.title].map(e).join(` `).trim().split(/\s+/).filter(Boolean).length;return`${Math.max(1,Math.ceil(n/200))} phút đọc`}export{t};